noncompliant:
template<typename T>
void process(T callback) noexcept {
  callback(); // Noncompliant: callback may throw, violating noexcept
}

class Base {
public:
  virtual void method() noexcept = 0;
};

class Derived : public Base {
public:
  void method() override; // Noncompliant: missing noexcept in override
};

compliant:
template<typename T>
void process(T callback) noexcept(noexcept(callback())) {
  callback(); // Compliant: conditional noexcept based on callback
}

class Base {
public:
  virtual void method() noexcept = 0;
};

class Derived : public Base {
public:
  void method() noexcept override; // Compliant: consistent exception spec
};
